import{_ as r,o as t,c as a,ak as n}from"./chunks/framework.sV-XtlWr.js";const g=JSON.parse('{"title":"Timeline markers","description":"","frontmatter":{"title":"Timeline markers","lang":"en-US"},"headers":[],"relativePath":"timeline-markers.md","filePath":"timeline-markers.md","lastUpdated":1784755405000}'),o={name:"timeline-markers.md"};function i(s,e,l,h,c,d){return t(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="timeline-markers" tabindex="-1">Timeline markers <a class="header-anchor" href="#timeline-markers" aria-label="Permalink to &quot;Timeline markers&quot;">​</a></h1><p>Timeline markers let you record <strong>dated events</strong> against a project — a deploy, a config change, an infrastructure migration, a dependency bump, an incident — and see them overlaid as vertical lines on the analytics trend charts. When a pass-rate drop or a performance regression lines up with a marker, you have your prime suspect: &quot;the slowdown started the day we switched CI runners&quot;.</p><h2 id="what-a-marker-is" tabindex="-1">What a marker is <a class="header-anchor" href="#what-a-marker-is" aria-label="Permalink to &quot;What a marker is&quot;">​</a></h2><p>Each marker belongs to one project and carries:</p><ul><li><strong>Label</strong> — a short title (e.g. <em>Migrated CI to ARM runners</em>).</li><li><strong>Date &amp; time</strong> — when the event happened; this is where the line is drawn.</li><li><strong>Category</strong> — one of <code>deploy</code>, <code>config</code>, <code>infra</code>, <code>incident</code>, <code>release</code>, or a generic <code>event</code>. The category sets the marker&#39;s icon and color.</li><li><strong>Environment</strong> <em>(optional)</em> — scope the marker to a single environment (e.g. <code>staging</code>). Leave it empty to apply to all environments.</li><li><strong>Description</strong> <em>(optional)</em> — free-text detail.</li></ul><h2 id="where-markers-show-up" tabindex="-1">Where markers show up <a class="header-anchor" href="#where-markers-show-up" aria-label="Permalink to &quot;Where markers show up&quot;">​</a></h2><ul><li><strong>Project charts</strong> — the <strong>Run trend</strong> and <strong>Performance trend</strong> charts render each marker as a dashed vertical line with a colored flag handle. Hover the handle for the marker&#39;s details; click it to jump to the Timeline tab and edit it.</li><li><strong>Timeline tab</strong> — every project has a <strong>Timeline</strong> tab listing its markers, with add / edit / delete controls.</li><li><strong>Test-case history</strong> — a single test&#39;s duration history chart shows the same markers, so you can tell whether an event affected that specific test.</li><li><strong>Run detail</strong> — a run shows an <strong>&quot;After: …&quot;</strong> chip for the nearest preceding marker, so a single run tells you which event it followed.</li><li><strong>Run compare</strong> — comparing two runs surfaces any markers that fall between them (&quot;something changed between these runs&quot;).</li></ul><h2 id="environment-scoping" tabindex="-1">Environment scoping <a class="header-anchor" href="#environment-scoping" aria-label="Permalink to &quot;Environment scoping&quot;">​</a></h2><p>Markers tie into the project&#39;s existing <strong>environment filter</strong>. When you filter the project view to one or more environments, the charts show only markers that match the selected environment(s) plus any global (no-environment) markers. This keeps a staging-only event from cluttering your production view.</p><p>The environment field is free text, with suggestions drawn from the environments already seen in the project&#39;s runs (set via the reporter&#39;s <code>environment</code> option / <code>PIWI_ENVIRONMENT</code>).</p><h2 id="who-can-edit-markers" tabindex="-1">Who can edit markers <a class="header-anchor" href="#who-can-edit-markers" aria-label="Permalink to &quot;Who can edit markers&quot;">​</a></h2><p>Reading markers is available to any signed-in user with access to the project. Creating, editing, and deleting them requires the <strong>reporter</strong> or <strong>administrator</strong> role. (When authentication is disabled, everyone can edit.)</p><h2 id="automatic-markers" tabindex="-1">Automatic markers <a class="header-anchor" href="#automatic-markers" aria-label="Permalink to &quot;Automatic markers&quot;">​</a></h2><p>Piwi can create markers for you when a run&#39;s tooling changes. On each finished run it compares the run against the previous run <strong>in the same environment</strong> and, when the <strong>Playwright version</strong> or <strong>reporter version</strong> changed, adds an <code>auto</code> marker (category <code>config</code>) at that run&#39;s time — for example <em>Playwright 1.49.0 → 1.50.0</em>. Auto markers are labeled with a small sparkle icon and can be edited or deleted like any other.</p><p>This is enabled by default. Set <code>PIWI_AUTO_MARKERS=false</code> to turn it off. See the <a href="./configuration.html">configuration reference</a>.</p><h2 id="api" tabindex="-1">API <a class="header-anchor" href="#api" aria-label="Permalink to &quot;API&quot;">​</a></h2><p>Markers are managed through the REST API (<code>GET</code>/<code>POST /api/projects/:id/markers</code>, <code>PUT</code>/<code>DELETE /api/markers/:id</code>). See the interactive <a href="https://piwitests.github.io/demo/docs" target="_blank" rel="noreferrer">API docs</a> for request and response shapes.</p>',17)])])}const p=r(o,[["render",i]]);export{g as __pageData,p as default};
